import{c as t,Q as a,j as r,m as i}from"./chunks/framework.BXc4yaFE.js";const b=JSON.parse('{"title":"Agentic Harness Engineering: Observability-Driven Automatic Evolution of Coding-Agent Harnesses","description":"","frontmatter":{"title":"Agentic Harness Engineering: Observability-Driven Automatic Evolution of Coding-Agent Harnesses","source_tier":"P"},"headers":[],"relativePath":"research/agent-harness/references/2604.25850-ahe-observability-arxiv.md","filePath":"research/agent-harness/references/2604.25850-ahe-observability-arxiv.md","lastUpdated":1779796674000}'),n={name:"research/agent-harness/references/2604.25850-ahe-observability-arxiv.md"};function s(o,e,l,d,h,c){return a(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="agentic-harness-engineering-observability-driven-automatic-evolution-of-coding-agent-harnesses" tabindex="-1">Agentic Harness Engineering: Observability-Driven Automatic Evolution of Coding-Agent Harnesses <a class="header-anchor" href="#agentic-harness-engineering-observability-driven-automatic-evolution-of-coding-agent-harnesses" aria-label="Permalink to &quot;Agentic Harness Engineering: Observability-Driven Automatic Evolution of Coding-Agent Harnesses&quot;">​</a></h1><ul><li><strong>arXiv</strong>: <a href="https://arxiv.org/abs/2604.25850" target="_blank" rel="noreferrer">https://arxiv.org/abs/2604.25850</a></li><li><strong>收錄日期</strong>: 2026-05-01</li><li><strong>發表</strong>: 2026-04</li><li><strong>重要性</strong>: Priority A — 本領域最新 SOTA，直接量化 harness 工程的效益</li></ul><hr><h2 id="核心論點" tabindex="-1">核心論點 <a class="header-anchor" href="#核心論點" aria-label="Permalink to &quot;核心論點&quot;">​</a></h2><p>Harness 改進應由<strong>工具、中介軟體和長期記憶</strong>主導，而非系統提示詞。提出 AHE（Agentic Harness Engineering）框架，透過三個可觀測性柱子自動進化 agent harnesses。</p><h2 id="三大可觀測性柱子" tabindex="-1">三大可觀測性柱子 <a class="header-anchor" href="#三大可觀測性柱子" aria-label="Permalink to &quot;三大可觀測性柱子&quot;">​</a></h2><ol><li><strong>元件可觀測性（Component Observability）</strong>: 檔案級表示、明確動作空間、可逆性設計</li><li><strong>經驗可觀測性（Experience Observability）</strong>: 執行軌跡資料 → 分層證據語料庫</li><li><strong>決策可觀測性（Decision Observability）</strong>: 編輯 + 自我宣告預測 + 事後驗證</li></ol><h2 id="關鍵成果" tabindex="-1">關鍵成果 <a class="header-anchor" href="#關鍵成果" aria-label="Permalink to &quot;關鍵成果&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Benchmark</th><th>優化前</th><th>優化後</th><th>提升</th></tr></thead><tbody><tr><td>Terminal-Bench 2 pass@1</td><td>69.7%</td><td>77.0%</td><td>+7.3 pp（10 次迭代）</td></tr><tr><td>SWE-bench-verified</td><td>baseline</td><td>SOTA</td><td>用 12% 更少 token</td></tr><tr><td>跨模型族遷移</td><td>—</td><td>—</td><td>+5.1 到 +10.1 pp</td></tr></tbody></table><h2 id="核心洞見" tabindex="-1">核心洞見 <a class="header-anchor" href="#核心洞見" aria-label="Permalink to &quot;核心洞見&quot;">​</a></h2><ul><li>將每次編輯轉成可驗證的合約，harness 演進可自動進行</li><li>超越人工設計的 Codex-CLI（71.9%），達到 77.0%</li><li>證明 harness 優化的效果與跨模型族遷移能力</li></ul><h2 id="與本-workspace-的關聯" tabindex="-1">與本 Workspace 的關聯 <a class="header-anchor" href="#與本-workspace-的關聯" aria-label="Permalink to &quot;與本 Workspace 的關聯&quot;">​</a></h2><ul><li>驗證 FRAMEWORK.md 的「Harness &gt; Model」命題</li><li>三大可觀測性柱子對應本 workspace 的：hooks（元件）、RESEARCH.md（經驗）、deep-review（決策）</li><li>支持「自動 Ratchet 演進」的學術依據</li></ul><h2 id="參考連結" tabindex="-1">參考連結 <a class="header-anchor" href="#參考連結" aria-label="Permalink to &quot;參考連結&quot;">​</a></h2><ul><li>arXiv Abstract: <a href="https://arxiv.org/abs/2604.25850" target="_blank" rel="noreferrer">https://arxiv.org/abs/2604.25850</a></li></ul>',15)])])}const u=t(n,[["render",s]]);export{b as __pageData,u as default};
